def sanitize_endpoint(path):
    """
    Normalize endpoint paths to prevent high cardinality.
    e.g., /users/12345 -> /users/:id
    """
    import re

    path = re.sub(r"/users/[^/]+", "/users/:id", path)
    path = re.sub(r"/orders/[^/]+", "/orders/:id", path)
    path = re.sub(r"/items/[^/]+", "/items/:id", path)
    # Add more patterns as needed for your API
    return path


@app.before_request
def before_request_metrics():
    """Record request start time and increment in-progress gauge."""
    g.start_time = time.time()
    endpoint = sanitize_endpoint(request.path)

    # Skip metrics endpoint itself to avoid recursion
    if endpoint == "/metrics":
        return

    REQUESTS_IN_PROGRESS.labels(
        method=request.method,
        endpoint=endpoint,
    ).inc()

    # Record request size (size only, NOT content)
    content_length = request.content_length or 0
    REQUEST_SIZE.labels(
        method=request.method,
        endpoint=endpoint,
    ).observe(content_length)


@app.after_request
def after_request_metrics(response):
    """Record request metrics after completion."""
    endpoint = sanitize_endpoint(request.path)

    if endpoint == "/metrics":
        return response

    # Calculate latency
    latency = time.time() - getattr(g, "start_time", time.time())

    REQUEST_COUNT.labels(
        method=request.method,
        endpoint=endpoint,
        status_code=response.status_code,
    ).inc()

    REQUEST_LATENCY.labels(
        method=request.method,
        endpoint=endpoint,
    ).observe(latency)

    REQUESTS_IN_PROGRESS.labels(
        method=request.method,
        endpoint=endpoint,
    ).dec()

    # Record response size
    response_size = response.content_length or 0
    RESPONSE_SIZE.labels(
        method=request.method,
        endpoint=endpoint,
    ).observe(response_size)

    # Track auth failures by type (not by user)
    if response.status_code == 401:
        AUTH_FAILURES.labels(
            method=request.method,
            endpoint=endpoint,
            failure_reason="invalid_credentials",
        ).inc()
    elif response.status_code == 403:
        AUTH_FAILURES.labels(
            method=request.method,
            endpoint=endpoint,
            failure_reason="forbidden",
        ).inc()
    elif response.status_code == 429:
        RATE_LIMITED_REQUESTS.labels(
            method=request.method,
            endpoint=endpoint,
        ).inc()

    return response


